var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"...타기리온.","JPN":"……タギリオン。","ENG":"...Thagirion.","TWN":"……塔基里翁。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"신성으로 만든 장벽 속에 꽁꽁 숨어있는 줄 알았는데, 이런 타이밍에 모습을 드러낼 줄은 몰랐어요.","JPN":"神聖で作った障壁の中に密かに隠れているだろうとは思いましたが、こんなタイミングで姿を現すとは思いませんでした。","ENG":"I thought you were hiding tightly behind a barrier made of divinity. I didn't expect you to show yourself at a time like this.","TWN":"我還以為你會一直躲在神性打造的城牆裡，沒想到會在這時候現身。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"대적자.","JPN":"敵対者。","ENG":"Antagonist.","TWN":"敵對者。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"잘도 늑대를 이용해서, 게임의 규칙을 피하고 마왕의 힘을 갈취했더군요.","JPN":"よくもオオカミを利用してゲームのルールを迂回し、魔王の力を奪い取りましたね。","ENG":"You used the Wolf well to avoid the rules of the game and steal the Demon Lord's power.","TWN":"你竟然利用狼避開遊戲規則，奪走了魔王的力量。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"주인공이 마왕과 싸워서 이기는 이야긴 이제 좀 식상하니, 반전 포인트를 줬을 뿐입니다.","JPN":"主人公が魔王と戦って勝つというストーリーはマンネリ化していますから、予想を裏切る展開にしてみただけです。","ENG":"Stories where the hero fights the Demon Lord and wins are a bit overdone these days, so I just added a twist.","TWN":"主角打敗魔王的劇情太老套了，我只是加點反轉而已。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"게임의 주최자 분께선 오히려 식상한 쪽을 좋아하시는 것 같았지만 말이죠.","JPN":"ゲームの主催者は、そんなマンネリ化したストーリーも結構お好きなようですが。","ENG":"Though it seems the host of this game is rather fond of such predictable stories.","TWN":"雖然遊戲主辦者似乎也很喜歡那種老套的劇情。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"제 심장도 가지러 온 건가요?","JPN":"私の心臓も取りに来たんですか？","ENG":"Did you come to take my heart as well?","TWN":"你也是來取我的心臟嗎？"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"머리든 심장이든 상관 없습니다.","JPN":"頭だろうが心臓だろうが構いません。","ENG":"Your head or your heart, it makes no difference.","TWN":"不管是頭還是心臟都無所謂。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"하지만, 클리포트 게임을 피해 도망친 마왕님께서 순순히 승부를 받아줄 것 같진 않군요.","JPN":"ですが、クリフォトゲームへの参加を避けて逃げた魔王様が大人しく勝負に乗ってくれるとは思いませんね。","ENG":"But I doubt a Demon Lord who fled the Qliphoth Game would agree to a fair match so easily.","TWN":"但逃離逆卡巴拉遊戲的魔王，應該不會乖乖正面對決吧。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그 말대로, 전 당신들과 정면으로 싸울 필요가 없어요.","JPN":"あなたの言う通り、私はあなたたちと真っ向勝負をする必要がありません。","ENG":"As you said, there's no need for me to fight you head-on.","TWN":"沒錯，我沒必要和你們正面交手。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"클리포트 게임 같은 명분 따윈 저에게 아무런 의미가 없었으니까요.","JPN":"クリフォトゲームなどという口実は、私にとって何の意味もありませんから。","ENG":"A pretext like the Qliphoth Game never meant anything to me in the first place.","TWN":"逆卡巴拉遊戲那種東西，對我毫無意義。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...그렇겠지.","JPN":"……だろうね。","ENG":"...That makes sense.","TWN":"……也是。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"당신이 바라는 건 소원이 아니라... 세계를 부수는 걸 테니까.","JPN":"あなたは願いを叶えたいんじゃなくて……世界を壊したいんだから。","ENG":"What you want isn't a wish... it's to destroy the world.","TWN":"你想要的不是願望，而是毀滅世界。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"울브즈베인...","JPN":"ウルブズベイン……","ENG":"Wolvesbane...","TWN":"狼之災禍……"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그렇게 상처 입은 몸으로 사용하면 목숨이 위험할 텐데요?","JPN":"その状態で使えば、体にかかる負担が大きいはずですが。","ENG":"Using it in that state must be putting a heavy strain on your body.","TWN":"在那種狀態下使用，身體負擔很大吧？"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"쓸데없는 소리.","JPN":"私なら問題ない。","ENG":"I'm fine.","TWN":"我很好。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"피하지 말고 덤벼!","JPN":"だから、かかってこい！","ENG":"So come at me!","TWN":"所以上吧！"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"...아직은...","JPN":"……まだ……","ENG":"...Not yet.","TWN":"……還沒到……"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"...뭐?","JPN":"……え？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"큭! 이 빛은 뭐야?!","JPN":"くっ！　何だ、この光は！？","ENG":"Ugh! What is this light?!","TWN":"呃！這是什麼光？！"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"꼭대기의 광휘가... 아까보다 훨씬 강렬해지고 있어요.","JPN":"頂上の輝きが……さっきよりずっと強くなっています。","ENG":"The radiance from the summit... It's getting much stronger than before.","TWN":"山頂的光……比剛才更強烈了！"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"함선을 추락시킨 빛보다 더 강해질 수 있다고?","JPN":"艦船を墜落させた時のあれが最大じゃなかったってこと？","ENG":"So bringing down the ship wasn't even its max output?","TWN":"讓艦船墜落還不是極限嗎？"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"음...?","JPN":"ん……？","ENG":"Hmm...?","TWN":"嗯……？"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"미나 양! 몸이...!","JPN":"ミナさん！　体が……！","ENG":"Mina! Your body...!","TWN":"米娜小姐！你的身體……！"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐야, 이거?","JPN":"何これ？","ENG":"What is this?","TWN":"這是怎麼回事？"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"왜 내 몸이... 점점 사라지고 있는 거지?","JPN":"なんで私の体が……だんだん消えていく？","ENG":"Why is my body... gradually disappearing?","TWN":"為什麼我的身體……在逐漸消失？"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......!","JPN":"……！","ENG":"...!","TWN":"……！"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"관리자! 저건 설마...?","JPN":"管理者！　あれはまさか……？","ENG":"Administrator! Is this...?","TWN":"管理者！那該不會是……？"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"...그 설마가 맞을 걸세.","JPN":"……そのまさかだな。","ENG":"...It seems that's exactly what it is.","TWN":"……沒錯。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이곳에서 우린 다른 세계의 엑자일러나 다름없네. 그래서 존재가 상쇄되고 있는 거야.","JPN":"ここでの我々は異世界のエグザイラーも同然だ。だから存在が相殺されているんだ。","ENG":"Here, we're no different from Exiles from another world. That's why our existence is being nullified.","TWN":"在這裡，我們就像異界的流浪者，所以存在會被抵消。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"세계가... 우릴 물리적으로 상쇄한다고?","JPN":"世界が……私たちを物理的に相殺すると？","ENG":"The world itself... is physically canceling us out?","TWN":"世界……會直接抹除我們？"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"외부의 존재는 용납하지 않는 것이 세계의 법칙이니까.","JPN":"外部からの存在を許さないのが、世界の法則だからね。","ENG":"The law of the world doesn't permit the existence of outsiders.","TWN":"世界的法則本來就不允許外來的存在。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"우릴 제 발로 여기까지 오게 만든 게... 처음부터 네 녀석의 의도였나?","JPN":"私たちが進んでここに来ること……最初からこれがやつの意図だったのか？","ENG":"Did she intend for us to come here on our own from the very beginning?","TWN":"難道我們來到這裡，本來就是她的計畫？"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"맞아요.","JPN":"そうです。","ENG":"That's right.","TWN":"沒錯。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"제 힘은 당신들 모두를 상대하기에 충분하지만... 오만이라는 실책을 되풀이할 생각은 없거든요.","JPN":"私の力はあなたたち全員を相手にしても問題ないのですが……傲慢という失敗を繰り返したくはないので。","ENG":"My power is more than enough to deal with all of you... But I have no intention of repeating the mistake of arrogance.","TWN":"雖然我的力量足以對付你們所有人……但我不會再因為傲慢犯錯。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그러니-","JPN":"ですから……","ENG":"So...","TWN":"所以—"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"가장 거슬리는 것을 먼저 배제해둘 생각입니다.","JPN":"最も厄介なものを、真っ先に排除するつもりです。","ENG":"I'll eliminate the most troublesome one first.","TWN":"先排除最麻煩的目標。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"크윽...!","JPN":"くっ……！","ENG":"Kgh...!","TWN":"咳……！"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"타기리온!!","JPN":"タギリオン！！","ENG":"Thagirion!!","TWN":"塔基里翁！！"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_11"},{"id":"L3_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"미나가... 사라졌어?","JPN":"ミナが……消えた？","ENG":"Mina... disappeared?","TWN":"米娜……消失了？"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"설마, 죽은 거야?","JPN":"まさか、死んだの？","ENG":"Did she– Did she die?","TWN":"難道死掉了嗎？"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"타기리온...!","JPN":"タギリオン……！","ENG":"Thagirion...!","TWN":"塔基里翁……！"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"...이제, 당신 차례에요.","JPN":"……次はあなたの番です。","ENG":"...Now it's your turn.","TWN":"……現在，輪到你了。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이 검기는?","JPN":"この剣気は？","ENG":"This sword energy...","TWN":"這劍氣是？"},"stage":{"bg":"PATH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"오래 기다렸다.","JPN":"待たせたのう。","ENG":"I've waited a long time.","TWN":"我等好久了。"},"stage":{"bg":"PATH","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"힐데.","JPN":"ヒルデ。","ENG":"Hilde.","TWN":"希爾德。"},"stage":{"bg":"PATH","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_COMBAT_ALL_FIRE_05"},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"마왕이 하나 더 있다고?","JPN":"魔王がもう一人いる？","ENG":"There's another Demon Lord?","TWN":"還有一個魔王？"},"stage":{"bg":"PATH","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"...아스모데우스.","JPN":"……アスモデウス。","ENG":"...Asmodeus.","TWN":"……阿斯蒙蒂斯。"},"stage":{"bg":"PATH","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"언제부터 네 녀석이 암군과 한통속이었지?","JPN":"貴様、いつから暗君と手を組んだ？","ENG":"Since when were you working with the Ignorant Monarch?","TWN":"你什麼時候和暗君聯手了？"},"stage":{"bg":"PATH","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"너와 내가 끝을 봐야 한다는 걸 알게 된 순간부터려나?","JPN":"其方と妾は決着をつけるべきと分かった瞬間からかのう？","ENG":"Since the moment I realized you and I had to settle things to the end.","TWN":"從我知道必須和你分出勝負的那一刻起。"},"stage":{"bg":"PATH","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"시기가 나쁘군. 너한테 낭비할 시간 없다.","JPN":"時期が悪かったな。貴様にくれてやる時間はない。","ENG":"The timing's bad. I don't have time to waste on you.","TWN":"時機不好，我沒時間浪費在你身上。"},"stage":{"bg":"PATH","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"이만큼 좋은 시기도 없지. 늑대가 사라진 이상, 넌 날 꺾기 위해 전력을 다해야 할 테니까.","JPN":"これほど良い時期もなかろう。オオカミが消えたからには、其方は妾を倒すために全力を尽くさねばならんからのう。","ENG":"There's no better timing than this. Now that the Wolf is gone, you'll have to go all out to defeat me.","TWN":"不，沒有比現在更好的時候了。沒有狼的你，必須全力以赴對付我。"},"stage":{"bg":"PATH","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PATH","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"금방 돌아올 테니 조금만 버텨라, 관리자.","JPN":"すぐに戻ってくる。少しだけ耐えてくれ、管理者。","ENG":"I'll be back soon. Hold out a little longer, Administrator.","TWN":"我很快就回來，只要撐一下就好，管理者。"},"stage":{"bg":"PATH","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"...알겠네.","JPN":"……分かった。","ENG":"...Understood.","TWN":"……我知道了。"},"stage":{"bg":"PATH","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"아하하하! 그 모습은 간만인걸!","JPN":"あははは！　久々にその姿を見るのう！","ENG":"Ahahahaha! I haven't seen that look in a while!","TWN":"哈哈哈哈！好久沒看到你這個樣子了！"},"stage":{"bg":"PATH","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"네가 가장 싫어하는 녀석이 내어준 그 권능을- 결국 쓸 셈이구나?","JPN":"其方が最も嫌う奴に与えられたその権能……結局は使うのじゃな？","ENG":"So you're finally going to use the power granted by the one you hate most?","TWN":"那個你最討厭的傢伙給你的力量，你終於要使用了嗎？"},"stage":{"bg":"PATH","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"그래. 널 들판으로 데려가마.","JPN":"ああ。貴様を野原へ導こう。","ENG":"Yes. I will guide you to my field.","TWN":"沒錯。我會把你帶到戰場。"},"stage":{"bg":"PATH","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_CA_PR_NULL","text":{"KOREA":"그곳이라면 아무도 우릴 방해하지 못할 테니.","JPN":"そこなら誰にも邪魔されないだろうからな。","ENG":"There, no one will be able to interfere with us.","TWN":"在那裡，沒有人能妨礙我們。"},"stage":{"bg":"PATH","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_CA_PR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"둘 중 하나만 살아 나올 수 있는 발키리의 들판이라.","JPN":"一人しか生きて帰ってこれないヴァルキリーの野原か。","ENG":"The Valkyrie's field where only one of us can walk out alive.","TWN":"我們之中只有一個人能活著走出的女武神戰場啊。"},"stage":{"bg":"PATH","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROSARIA_FALLEN_CA_NULL","text":{"KOREA":"못 다한 시험을 마무리 짓기 좋은 기회겠군.","JPN":"やり残した試練にけじめを付けるにはいいチャンスじゃ。","ENG":"A perfect chance to finish the test we never completed.","TWN":"正好，用來完成未完的試煉。"},"stage":{"bg":"PATH","bgm":"THEMA_CA_ROSARIA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PATH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"뭐지? 빛에 빨려 들어갔어?","JPN":"何？　光に吸い込まれた？","ENG":"What was that? They got pulled into the light?","TWN":"什麼？被光吸進去了？"},"stage":{"bg":"PATH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"스승님은... 무사하시겠죠?","JPN":"師匠……無事ですよね。","ENG":"Master... Will she be all right?","TWN":"師父她……應該沒事吧？"},"stage":{"bg":"PATH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"잠시 아공간으로 전송된 걸세.","JPN":"しばらく亜空間に転送されたんだ。","ENG":"They've been transferred to a dimensional pocket temporarily.","TWN":"她只是暫時被傳送到亞空間而已。"},"stage":{"bg":"PATH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"노엘 양이라면 그녀의 기운이 아직 이곳에 있단 걸 알 수 있겠지.","JPN":"ノエル君なら、彼女の気配がまだここにいることが分かるだろう。","ENG":"Noelle, you should still be able to sense her presence here.","TWN":"如果是洛艾兒小姐，應該能感覺到她的氣息還在這裡。"},"stage":{"bg":"PATH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"...네. 한 꺼풀 너머에서 소대장님의 기운이 느껴져요.","JPN":"……はい。薄い膜の向こうから小隊長の気配を感じます。","ENG":"...Yes. I can feel Commander's presence just beyond a thin boundary.","TWN":"……嗯。能隔著一層膜感覺到小隊長的氣息。"},"stage":{"bg":"PATH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그리고 별로 가깝진 않지만...","JPN":"それと、それほど近くはないけれど……","ENG":"And not very close, but...","TWN":"而且雖然不算近……"},"stage":{"bg":"PATH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"미나 선배의 기운도 희미하게 남아있어요.","JPN":"ミナ先輩の気配も微かに残っています。","ENG":"I can faintly sense Mina's presence too.","TWN":"也還殘留著一點點米娜前輩的氣息。"},"stage":{"bg":"PATH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"뭐? 미나가 아직 어딘가에 살아있단 뜻이야?","JPN":"え？　それって、ミナはまだどこかに生きてるってこと？","ENG":"What? Does that mean Mina is still alive somewhere?","TWN":"什麼？意思是米娜沒死，還在某個地方嗎？"},"stage":{"bg":"PATH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"늑대는 골칫거리지만, 아예 소멸시키는 건 저한테도 곤란하거든요.","JPN":"オオカミは確かに厄介ですが、消滅されると私も困りますから。","ENG":"The Wolf is troublesome, but completely erasing her would be inconvenient even for me.","TWN":"那隻狼確實很棘手。不過徹底消滅她，對我來說也有點困擾。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SERGEANT_GRONIA_NULL_NULL","text":{"KOREA":"무슨 꿍꿍이로 미나 씨를 데려 간 거죠?","JPN":"ミナさんに……何をしたんですか？","ENG":"What... did you do to Mina?","TWN":"你……對米娜做了什麼？"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERGEANT_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"글쎄요.","JPN":"さあ。","ENG":"Who knows.","TWN":"有可能。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"여기서 살아남지 못한다면, 그 다음에 일어날 일들 따위가 다 무슨 소용일까요?","JPN":"ここで私と戦い、生き延びれなかったら、その後に起こることを知っても意味がないでしょう。","ENG":"If you can't survive against me here, what use would anything that happens afterward be anyway?","TWN":"如果你們連在這裡都活不了，那之後會發生什麼，又有什麼意義呢？"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"그러니 먼저 증명해보세요.","JPN":"だから先に証明してください。","ENG":"So prove it first.","TWN":"所以，先證明給我看吧。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOLL_NPC_NULL_NULL","text":{"KOREA":"당신들에게, 다음이라는 기회가 있을지.","JPN":"あなたたちに、次という機会があるかどうかを。","ENG":"Whether you even have the chance to see what comes next.","TWN":"你們，到底有沒有下一次的機會。"},"stage":{"bg":"PATH","bgm":"THEMA_MAESTRO_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOLL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};